 20→#[derive(Accounts)]
 21→pub struct NullifyLeaves<'info> {
 22→    /// CHECK: should only be accessed by a registered program or owner.
 23→    pub authority: Signer<'info>,
 24→    pub registered_program_pda: Option<Account<'info, RegisteredProgram>>,
 25→    /// CHECK: when emitting event.
 26→    pub log_wrapper: UncheckedAccount<'info>,
 27→    #[account(mut)]
 28→    pub merkle_tree: AccountLoader<'info, StateMerkleTreeAccount>,
 29→    #[account(mut)]
 30→    pub nullifier_queue: AccountLoader<'info, QueueAccount>,
 31→}
