 33→impl GroupAccess for StateMerkleTreeAccount {
 34→    fn get_owner(&self) -> Pubkey {
 35→        self.metadata.access_metadata.owner.into()
 36→    }
 37→
 38→    fn get_program_owner(&self) -> Pubkey {
 39→        self.metadata
