 56→pub fn process_nullify_leaves<'a, 'b, 'c: 'info, 'info>(
 57→    ctx: &'a Context<'a, 'b, 'c, 'info, NullifyLeaves<'info>>,
 58→    change_log_indices: &'a [u64],
 59→    leaves_queue_indices: &'a [u16],
 60→    leaf_indices: &'a [u64],
 61→    proofs: &'a [Vec<[u8; 32]>],
 62→) -> Result<()> {
 63→    if change_log_indices.len() != 1 {
 64→        msg!("only implemented for 1 nullifier update");
 65→        return Err(AccountCompressionErrorCode::NumberOfChangeLogIndicesMismatch.into());
 66→    }
 67→    if leaves_queue_indices.len() != change_log_indices.len() {
 68→        msg!("only implemented for 1 nullifier update");
 69→        return Err(AccountCompressionErrorCode::NumberOfLeavesMismatch.into());
 70→    }
 71→    if leaf_indices.len() != change_log_indices.len() {
 72→        msg!("only implemented for 1 nullifier update");
 73→        return Err(AccountCompressionErrorCode::NumberOfIndicesMismatch.into());
 74→    }
 75→    if proofs.len() != change_log_indices.len() {
 76→        msg!("only implemented for 1 nullifier update");
 77→        return Err(AccountCompressionErrorCode::NumberOfProofsMismatch.into());
 78→    }
 79→    if proofs.len() > 1 && proofs[0].len() != proofs[1].len() {
 80→        msg!(
 81→            "Proofs length mismatch {} {}",
 82→            proofs[0].len(),
 83→            proofs[1].len()
 84→        );
 85→        return Err(AccountCompressionErrorCode::ProofLengthMismatch.into());
 86→    }
 87→    insert_nullifier(
 88→        proofs,
 89→        change_log_indices,
 90→        leaves_queue_indices,
 91→        leaf_indices,
 92→        ctx,
 93→    )?;
 94→
 95→    Ok(())
 96→}
 97→
 98→#[inline(never)]
 99→fn insert_nullifier<'a, 'c: 'info, 'info>(
100→    proofs: &[Vec<[u8; 32]>],
101→    change_log_indices: &[u64],
102→    leaves_queue_indices: &[u16],
103→    leaf_indices: &[u64],
104→    ctx: &Context<'a, '_, 'c, 'info, NullifyLeaves<'info>>,
105→) -> Result<()> {
106→    {
107→        let merkle_tree = ctx.accounts.merkle_tree.load()?;
108→
109→        if merkle_tree.metadata.associated_queue != ctx.accounts.nullifier_queue.key() {
110→            msg!(
111→            "Merkle tree and nullifier queue are not associated. Merkle tree associated nullifier queue {:?} != nullifier queue {}",
112→            merkle_tree.metadata.associated_queue,
113→            ctx.accounts.nullifier_queue.key()
114→        );
115→            return err!(AccountCompressionErrorCode::MerkleTreeAndQueueNotAssociated);
116→        }
117→        check_signer_is_registered_or_authority::<NullifyLeaves, StateMerkleTreeAccount>(
118→            ctx,
119→            &merkle_tree,
120→        )?;
121→    }
122→
123→    let merkle_tree = ctx.accounts.merkle_tree.to_account_info();
124→    let mut merkle_tree = merkle_tree.try_borrow_mut_data()?;
125→    let mut merkle_tree = state_merkle_tree_from_bytes_zero_copy_mut(&mut merkle_tree)?;
126→
127→    let nullifier_queue = ctx.accounts.nullifier_queue.to_account_info();
128→    let mut nullifier_queue = nullifier_queue.try_borrow_mut_data()?;
129→    let mut nullifier_queue = unsafe { queue_from_bytes_zero_copy_mut(&mut nullifier_queue)? };
130→
131→    let allowed_proof_size = merkle_tree.height - merkle_tree.canopy_depth;
132→    if proofs[0].len() != allowed_proof_size {
133→        msg!(
134→            "Invalid Proof Length {} allowed height {} - canopy {} {}",
135→            proofs[0].len(),
136→            merkle_tree.height,
137→            merkle_tree.canopy_depth,
138→            allowed_proof_size,
139→        );
140→        return err!(AccountCompressionErrorCode::InvalidMerkleProof);
141→    }
142→    let seq = (merkle_tree.sequence_number() + 1) as u64;
143→    for (i, leaf_queue_index) in leaves_queue_indices.iter().enumerate() {
144→        let leaf_cell = nullifier_queue
145→            .get_unmarked_bucket(*leaf_queue_index as usize)
146→            .ok_or(AccountCompressionErrorCode::LeafNotFound)?
147→            .ok_or(AccountCompressionErrorCode::LeafNotFound)?;
148→
149→        let mut proof =
150→            from_vec(proofs[i].as_slice(), merkle_tree.height).map_err(ProgramError::from)?;
151→        merkle_tree
152→            .update(
153→                change_log_indices[i] as usize,
154→                &leaf_cell.value_bytes(),
155→                &ZERO_BYTES[0],
156→                leaf_indices[i] as usize,
157→                &mut proof,
158→            )
159→            .map_err(ProgramError::from)?;
160→
161→        nullifier_queue
162→            .mark_with_sequence_number(*leaf_queue_index as usize, merkle_tree.sequence_number())
163→            .map_err(ProgramError::from)?;
164→    }
165→    let nullify_event = NullifierEvent {
166→        id: ctx.accounts.merkle_tree.key().to_bytes(),
167→        nullified_leaves_indices: leaf_indices.to_vec(),
168→        seq,
169→    };
170→    let nullify_event = MerkleTreeEvent::V2(nullify_event);
171→    emit_indexer_event(nullify_event.try_to_vec()?, &ctx.accounts.log_wrapper)?;
172→    Ok(())
173→}
174→
175→#[inline(never)]
176→pub fn from_vec(vec: &[[u8; 32]], height: usize) -> Result<BoundedVec<[u8; 32]>> {
177→    let proof: [[u8; 32]; 16] = vec.try_into().unwrap();
178→    let mut bounded_vec = BoundedVec::with_capacity(height);
179→    bounded_vec.extend(proof).map_err(ProgramError::from)?;
180→    Ok(bounded_vec)
181→}
