184→pub mod sdk_nullify {
185→    use anchor_lang::{InstructionData, ToAccountMetas};
186→    use solana_sdk::{instruction::Instruction, pubkey::Pubkey};
187→
188→    use crate::utils::constants::NOOP_PUBKEY;
189→
190→    pub fn create_nullify_instruction(
191→        change_log_indices: &[u64],
192→        leaves_queue_indices: &[u16],
193→        leaf_indices: &[u64],
194→        proofs: &[Vec<[u8; 32]>],
195→        payer: &Pubkey,
196→        merkle_tree_pubkey: &Pubkey,
197→        nullifier_queue_pubkey: &Pubkey,
198→    ) -> Instruction {
199→        let instruction_data = crate::instruction::NullifyLeaves {
200→            leaves_queue_indices: leaves_queue_indices.to_vec(),
201→            leaf_indices: leaf_indices.to_vec(),
202→            change_log_indices: change_log_indices.to_vec(),
203→            proofs: proofs.to_vec(),
204→        };
205→
206→        let accounts = crate::accounts::NullifyLeaves {
207→            authority: *payer,
208→            registered_program_pda: None,
209→            log_wrapper: Pubkey::new_from_array(NOOP_PUBKEY),
210→            merkle_tree: *merkle_tree_pubkey,
211→            nullifier_queue: *nullifier_queue_pubkey,
212→        };
213→
214→        Instruction {
215→            program_id: crate::ID,
216→            accounts: accounts.to_account_metas(Some(true)),
217→            data: instruction_data.data(),
218→        }
219→    }
220→}
