 41→pub struct EpochManagerTransactions<R: Rpc> {
 42→    pub pool: Arc<SolanaRpcPool<R>>,
 43→    pub epoch: u64,
 44→    pub phantom: std::marker::PhantomData<R>,
 45→    pub processed_hash_cache: Arc<Mutex<ProcessedHashCache>>,
 46→}
 47→
 48→impl<R: Rpc> EpochManagerTransactions<R> {
 49→    pub fn new(
 50→        pool: Arc<SolanaRpcPool<R>>,
 51→        epoch: u64,
 52→        cache: Arc<Mutex<ProcessedHashCache>>,
 53→    ) -> Self {
 54→        Self {
 55→            pool,
 56→            epoch,
 57→            phantom: std::marker::PhantomData,
 58→            processed_hash_cache: cache,
 59→        }
 60→    }
 61→}
 62→
 63→#[async_trait]
 64→impl<R: Rpc> TransactionBuilder for EpochManagerTransactions<R> {
 65→    fn epoch(&self) -> u64 {
 66→        self.epoch
 67→    }
 68→
 69→    async fn build_signed_transaction_batch(
 70→        &self,
 71→        payer: &Keypair,
 72→        derivation: &Pubkey,
 73→        recent_blockhash: &Hash,
 74→        last_valid_block_height: u64,
 75→        priority_fee: u64,
 76→        work_items: &[WorkItem],
 77→        config: BuildTransactionBatchConfig,
 78→    ) -> Result<(Vec<Transaction>, u64)> {
 79→        let mut cache = self.processed_hash_cache.lock().await;
 80→
 81→        let work_items: Vec<&WorkItem> = work_items
 82→            .iter()
 83→            .filter(|item| {
 84→                let hash_str = bs58::encode(&item.queue_item_data.hash).into_string();
 85→                if cache.contains(&hash_str) {
 86→                    trace!("Skipping already processed hash: {}", hash_str);
 87→                    false
 88→                } else {
 89→                    true
 90→                }
 91→            })
 92→            .collect();
 93→
 94→        // Add items with short timeout (30 seconds) for processing
 95→        for item in &work_items {
 96→            let hash_str = bs58::encode(&item.queue_item_data.hash).into_string();
 97→            cache.add_with_timeout(&hash_str, Duration::from_secs(15));
 98→            trace!("Added {} to cache with 15s timeout", hash_str);
 99→        }
100→
101→        let work_item_hashes: Vec<String> = work_items
102→            .iter()
103→            .map(|item| bs58::encode(&item.queue_item_data.hash).into_string())
104→            .collect();
105→
106→        drop(cache);
107→
108→        if work_items.is_empty() {
109→            trace!("All items in this batch were recently processed, skipping batch");
110→            return Ok((vec![], last_valid_block_height));
111→        }
112→
113→        let work_items = work_items
114→            .iter()
115→            .map(|&item| item.clone())
116→            .collect::<Vec<_>>();
117→
118→        let mut transactions = vec![];
119→        let all_instructions = match fetch_proofs_and_create_instructions(
120→            payer.pubkey(),
121→            *derivation,
122→            self.pool.clone(),
123→            self.epoch,
124→            work_items.as_slice(),
125→        )
126→        .await
127→        {
128→            Ok((_, instructions)) => instructions,
129→            Err(e) => {
130→                // Check if it's a "Record Not Found" error
131→                let err_str = e.to_string();
132→                return if err_str.to_lowercase().contains("record not found")
133→                    || err_str.to_lowercase().contains("not found")
134→                {
135→                    warn!("Record not found in indexer, skipping batch: {}", e);
136→                    // Return empty transactions but don't propagate the error
137→                    Ok((vec![], last_valid_block_height))
138→                } else {
139→                    // For any other error, propagate it
140→                    Err(e)
141→                };
142→            }
143→        };
144→
145→        let batch_size = config.batch_size.max(1) as usize;
146→
147→        for instruction_chunk in all_instructions.chunks(batch_size) {
148→            let (transaction, _) = create_smart_transaction(CreateSmartTransactionConfig {
149→                payer: payer.insecure_clone(),
150→                instructions: instruction_chunk.to_vec(),
151→                recent_blockhash: *recent_blockhash,
152→                compute_unit_price: Some(priority_fee),
153→                compute_unit_limit: config.compute_unit_limit,
154→                last_valid_block_height,
155→            })
156→            .await?;
157→            transactions.push(transaction);
158→        }
159→
160→        if !transactions.is_empty() {
161→            let mut cache = self.processed_hash_cache.lock().await;
162→            for hash_str in work_item_hashes {
163→                cache.extend_timeout(&hash_str, Duration::from_secs(30));
164→                trace!(
165→                    "Extended cache timeout for {} to 30s after successful transaction creation",
166→                    hash_str
167→                );
168→            }
169→        }
170→
171→        Ok((transactions, last_valid_block_height))
172→    }
173→}
