 37→// doesn't keep its own Merkle tree but gets it from the indexer
 38→// can also get all the state and Address Merkle trees from the indexer
 39→// the lightweight version is just a function
 40→// we should have a random option that shuffles the order in which to nullify transactions
 41→// we should have a parameters how many to nullify
 42→// in the test we should nullify everything once the queue is 60% full
 43→
 44→/// Check compressed_accounts in the queue array which are not nullified yet
 45→/// Iterate over these compressed_accounts and nullify them
 46→///
 47→/// Checks:
 48→/// 1. Value in hashset is marked
 49→/// 2. State tree root is updated
 50→/// 3. TODO: add event is emitted (after rebase)
 51→///    optional: assert that the Merkle tree doesn't change except the updated leaf
 52→pub async fn nullify_compressed_accounts<R: Rpc + TestRpc + Indexer + Indexer>(
 53→    rpc: &mut R,
 54→    forester: &Keypair,
 55→    state_tree_bundle: &mut StateMerkleTreeBundle,
 56→    epoch: u64,
 57→    is_metadata_forester: bool,
 58→) -> Result<(), RpcError> {
 59→    let nullifier_queue = unsafe {
 60→        get_hash_set::<QueueAccount, R>(rpc, state_tree_bundle.accounts.nullifier_queue).await
 61→    }
 62→    .unwrap();
 63→    let pre_forester_counter = if is_metadata_forester {
 64→        0
 65→    } else {
 66→        rpc.get_anchor_account::<ForesterEpochPda>(
 67→            &get_forester_epoch_pda_from_authority(&forester.pubkey(), epoch).0,
 68→        )
 69→        .await
 70→        .unwrap()
 71→        .unwrap()
 72→        .work_counter
 73→    };
 74→    let onchain_merkle_tree =
 75→        get_concurrent_merkle_tree::<StateMerkleTreeAccount, R, Poseidon, 26>(
 76→            rpc,
 77→            state_tree_bundle.accounts.merkle_tree,
 78→        )
 79→        .await
 80→        .unwrap();
 81→    assert_eq!(
 82→        onchain_merkle_tree.root(),
 83→        state_tree_bundle.merkle_tree.root()
 84→    );
 85→    let pre_root = onchain_merkle_tree.root();
 86→    let change_log_index = onchain_merkle_tree.changelog_index() as u64;
 87→
 88→    let mut compressed_account_to_nullify = Vec::new();
 89→
 90→    let first = nullifier_queue.first_no_seq().unwrap();
 91→
 92→    for i in 0..nullifier_queue.get_capacity() {
 93→        let bucket = nullifier_queue.get_bucket(i).unwrap();
 94→        if let Some(bucket) = bucket {
 95→            if bucket.sequence_number.is_none() {
 96→                debug!("element to nullify: {:?}", bucket.value_bytes());
 97→                let leaf_index: usize = state_tree_bundle
 98→                    .merkle_tree
 99→                    .get_leaf_index(&bucket.value_bytes())
100→                    .unwrap();
101→                debug!("leaf_index: {:?}", leaf_index);
102→                compressed_account_to_nullify.push((i, bucket.value_bytes()));
103→            }
104→        }
105→    }
106→
107→    debug!(
108→        "nullifying {:?} accounts ",
109→        compressed_account_to_nullify.len()
110→    );
111→
112→    for (i, (index_in_nullifier_queue, compressed_account)) in
113→        compressed_account_to_nullify.iter().enumerate()
114→    {
115→        let leaf_index: usize = state_tree_bundle
116→            .merkle_tree
117→            .get_leaf_index(compressed_account)
118→            .unwrap();
119→        debug!("nullifying leaf: {:?}", leaf_index);
120→
121→        let proof: Vec<[u8; 32]> = state_tree_bundle
122→            .merkle_tree
123→            .get_proof_of_leaf(leaf_index, false)
124→            .unwrap();
125→        let ix = create_nullify_instruction(
126→            CreateNullifyInstructionInputs {
127→                authority: forester.pubkey(),
128→                nullifier_queue: state_tree_bundle.accounts.nullifier_queue,
129→                merkle_tree: state_tree_bundle.accounts.merkle_tree,
130→                change_log_indices: vec![change_log_index],
131→                leaves_queue_indices: vec![*index_in_nullifier_queue as u16],
132→                indices: vec![leaf_index as u64],
133→                proofs: vec![proof],
134→                derivation: forester.pubkey(),
135→                is_metadata_forester,
136→            },
137→            epoch,
138→        );
139→        let instructions = [ix];
140→
141→        let event = Rpc::create_and_send_transaction_with_event::<MerkleTreeEvent>(
142→            rpc,
143→            &instructions,
144→            &forester.pubkey(),
145→            &[forester],
146→        )
147→        .await?
148→        .unwrap();
149→
150→        match event.0 {
151→            MerkleTreeEvent::V2(event) => {
152→                assert_eq!(event.id, state_tree_bundle.accounts.merkle_tree.to_bytes());
153→                assert_eq!(
154→                    event.seq,
155→                    onchain_merkle_tree.sequence_number() as u64 + 1 + i as u64
156→                );
157→                assert_eq!(event.nullified_leaves_indices.len(), 1);
158→                assert_eq!(event.nullified_leaves_indices[0], leaf_index as u64);
159→            }
160→            _ => {
161→                panic!("Wrong event type.");
162→            }
163→        }
164→
165→        assert_value_is_marked_in_queue(
166→            rpc,
167→            state_tree_bundle,
168→            index_in_nullifier_queue,
169→            compressed_account,
170→        )
171→        .await;
172→    }
173→
174→    let num_nullified = compressed_account_to_nullify.len() as u64;
175→    // Locally nullify all leaves
176→    for (_, compressed_account) in compressed_account_to_nullify.iter() {
177→        let leaf_index = state_tree_bundle
178→            .merkle_tree
179→            .get_leaf_index(compressed_account)
180→            .unwrap();
181→        debug!("locally nullifying leaf_index {}", leaf_index);
182→        debug!("compressed_account {:?}", compressed_account);
183→        debug!(
184→            "merkle tree pubkey {:?}",
185→            state_tree_bundle.accounts.merkle_tree
186→        );
187→
188→        state_tree_bundle
189→            .merkle_tree
190→            .update(&[0u8; 32], leaf_index)
191→            .unwrap();
192→    }
193→    let onchain_merkle_tree =
194→        get_concurrent_merkle_tree::<StateMerkleTreeAccount, R, Poseidon, 26>(
195→            rpc,
196→            state_tree_bundle.accounts.merkle_tree,
197→        )
198→        .await
199→        .unwrap();
200→    assert_eq!(
201→        onchain_merkle_tree.root(),
202→        state_tree_bundle.merkle_tree.root()
203→    );
204→    if !is_metadata_forester {
205→        assert_forester_counter(
206→            rpc,
207→            &get_forester_epoch_pda_from_authority(&forester.pubkey(), epoch).0,
208→            pre_forester_counter,
209→            num_nullified,
210→        )
211→        .await
212→        .unwrap();
213→    }
214→    // SAFEGUARD: check that the root changed if there was at least one element to nullify
215→    if first.is_some() {
216→        assert_ne!(pre_root, onchain_merkle_tree.root());
217→    }
218→    Ok(())
219→}
