221→async fn assert_value_is_marked_in_queue<R: Rpc>(
222→    rpc: &mut R,
223→    state_tree_bundle: &mut StateMerkleTreeBundle,
224→    index_in_nullifier_queue: &usize,
225→    compressed_account: &[u8; 32],
226→) {
227→    let nullifier_queue = unsafe {
228→        get_hash_set::<QueueAccount, R>(rpc, state_tree_bundle.accounts.nullifier_queue).await
229→    }
230→    .unwrap();
231→    let array_element = nullifier_queue
232→        .get_bucket(*index_in_nullifier_queue)
233→        .unwrap()
234→        .unwrap();
235→    assert_eq!(&array_element.value_bytes(), compressed_account);
236→    let onchain_merkle_tree =
237→        get_concurrent_merkle_tree::<StateMerkleTreeAccount, R, Poseidon, 26>(
238→            rpc,
239→            state_tree_bundle.accounts.merkle_tree,
240→        )
241→        .await
242→        .unwrap();
243→    assert_eq!(
244→        array_element.sequence_number(),
245→        Some(
246→            onchain_merkle_tree.sequence_number()
247→                + onchain_merkle_tree.roots.capacity()
248→                + SAFETY_MARGIN as usize
249→        )
250→    );
251→}
