253→pub async fn assert_forester_counter<R: Rpc>(
254→    rpc: &mut R,
255→    pubkey: &Pubkey,
256→    pre: u64,
257→    num_nullified: u64,
258→) -> Result<(), RpcError> {
259→    let account = rpc
260→        .get_anchor_account::<ForesterEpochPda>(pubkey)
261→        .await?
262→        .unwrap();
263→    if account.work_counter != pre + num_nullified {
264→        debug!("account.work_counter: {}", account.work_counter);
265→        debug!("pre: {}", pre);
266→        debug!("num_nullified: {}", num_nullified);
267→        debug!("forester pubkey: {:?}", pubkey);
268→        return Err(RpcError::CustomError(
269→            "ForesterEpochPda counter not updated correctly".to_string(),
270→        ));
271→    }
272→    Ok(())
273→}
