280→/// Mocks the address insert logic of a forester.
281→/// Gets addresses from the AddressQueue and inserts them into the AddressMerkleTree.
282→///
283→/// Checks:
284→/// 1. Element has been marked correctly
285→/// 2. Merkle tree has been updated correctly
286→///
287→/// TODO: Event has been emitted, event doesn't exist yet
288→pub async fn empty_address_queue_test<R: Rpc>(
289→    forester: &Keypair,
290→    rpc: &mut R,
291→    address_tree_bundle: &mut AddressMerkleTreeBundle,
292→    signer_is_owner: bool,
293→    epoch: u64,
294→    is_metadata_forester: bool,
295→) -> Result<(), RelayerUpdateError> {
296→    let address_merkle_tree_pubkey = address_tree_bundle.accounts.merkle_tree;
297→    let address_queue_pubkey = address_tree_bundle.accounts.queue;
298→    let initial_merkle_tree_state = address_tree_bundle
299→        .get_v1_indexed_merkle_tree()
300→        .unwrap()
301→        .clone();
302→    let initial_indexed_array_state = address_tree_bundle.indexed_array_v1().unwrap().clone();
303→    let mut update_errors: Vec<RpcError> = Vec::new();
304→    let address_merkle_tree =
305→        get_indexed_merkle_tree::<AddressMerkleTreeAccount, R, Poseidon, usize, 26, 16>(
306→            rpc,
307→            address_merkle_tree_pubkey,
308→        )
309→        .await
310→        .unwrap();
311→    let indexed_changelog_index = address_merkle_tree.indexed_changelog_index() as u16;
312→    let changelog_index = address_merkle_tree.changelog_index() as u16;
313→    let mut counter = 0;
314→    loop {
315→        let pre_forester_counter = if !signer_is_owner {
316→            rpc.get_anchor_account::<ForesterEpochPda>(
317→                &get_forester_epoch_pda_from_authority(&forester.pubkey(), epoch).0,
318→            )
319→            .await
320→            .map_err(|e| RelayerUpdateError::RpcError)?
321→            .unwrap()
322→            .work_counter
323→        } else {
324→            0
325→        };
326→        let address_merkle_tree =
327→            get_indexed_merkle_tree::<AddressMerkleTreeAccount, R, Poseidon, usize, 26, 16>(
328→                rpc,
329→                address_merkle_tree_pubkey,
330→            )
331→            .await
332→            .unwrap();
333→        assert_eq!(address_tree_bundle.root(), address_merkle_tree.root());
334→        let address_queue =
335→            unsafe { get_hash_set::<QueueAccount, R>(rpc, address_queue_pubkey).await }.unwrap();
336→
337→        let address = address_queue.first_no_seq().unwrap();
338→
339→        if address.is_none() {
340→            break;
341→        }
342→        let (address, address_hashset_index) = address.unwrap();
343→        // Create new element from the dequeued value.
344→        let (old_low_address, old_low_address_next_value) = initial_indexed_array_state
345→            .find_low_element_for_nonexistent(&address.value_biguint())
346→            .unwrap();
347→        let address_bundle = initial_indexed_array_state
348→            .new_element_with_low_element_index(old_low_address.index, &address.value_biguint())
349→            .unwrap();
350→
351→        // Get the Merkle proof for updating low element.
352→        let low_address_proof = initial_merkle_tree_state
353→            .get_proof_of_leaf(old_low_address.index, false)
354→            .unwrap();
355→
356→        let old_sequence_number = address_merkle_tree.sequence_number();
357→        let old_root = address_merkle_tree.root();
358→        // Update on-chain tree.
359→        let update_successful = match update_merkle_tree(
360→            rpc,
361→            forester,
362→            address_queue_pubkey,
363→            address_merkle_tree_pubkey,
364→            address_hashset_index,
365→            old_low_address.index as u64,
366→            bigint_to_be_bytes_array(&old_low_address.value).unwrap(),
367→            old_low_address.next_index as u64,
368→            bigint_to_be_bytes_array(&old_low_address_next_value).unwrap(),
369→            low_address_proof.to_array().unwrap(),
370→            Some(changelog_index),
371→            Some(indexed_changelog_index),
372→            signer_is_owner,
373→            epoch,
374→            is_metadata_forester,
375→        )
376→        .await
377→        {
378→            Ok(event) => {
379→                let event = event.unwrap();
380→                match event.0 {
381→                    MerkleTreeEvent::V3(event) => {
382→                        // Only assert for the first update since the other updates might be patched
383→                        // the asserts are likely to fail
384→                        if counter == 0 {
385→                            assert_eq!(event.id, address_merkle_tree_pubkey.to_bytes());
386→                            assert_eq!(event.seq, old_sequence_number as u64 + 1);
387→                            assert_eq!(event.updates.len(), 1);
388→                            let event = &event.updates[0];
389→                            assert_eq!(
390→                                event.new_low_element.index, address_bundle.new_low_element.index,
391→                                "Empty Address Queue Test: invalid new_low_element.index"
392→                            );
393→                            assert_eq!(
394→                                event.new_low_element.next_index,
395→                                address_bundle.new_low_element.next_index,
396→                                "Empty Address Queue Test: invalid new_low_element.next_index"
397→                            );
398→                            assert_eq!(
399→                                event.new_low_element.value,
400→                                bigint_to_be_bytes_array::<32>(
401→                                    &address_bundle.new_low_element.value
402→                                )
403→                                .unwrap(),
404→                                "Empty Address Queue Test: invalid new_low_element.value"
405→                            );
406→                            assert_eq!(
407→                                event.new_low_element.next_value,
408→                                bigint_to_be_bytes_array::<32>(&address_bundle.new_element.value)
409→                                    .unwrap(),
410→                                "Empty Address Queue Test: invalid new_low_element.next_value"
411→                            );
412→                            let leaf_hash = address_bundle
413→                                .new_low_element
414→                                .hash::<Poseidon>(&address_bundle.new_element.value)
415→                                .unwrap();
416→                            assert_eq!(
417→                                event.new_low_element_hash, leaf_hash,
418→                                "Empty Address Queue Test: invalid new_low_element_hash"
419→                            );
420→                            let leaf_hash = address_bundle
421→                                .new_element
422→                                .hash::<Poseidon>(&address_bundle.new_element_next_value)
423→                                .unwrap();
424→                            assert_eq!(
425→                                event.new_high_element_hash, leaf_hash,
426→                                "Empty Address Queue Test: invalid new_high_element_hash"
427→                            );
428→                            assert_eq!(
429→                                event.new_high_element.index, address_bundle.new_element.index,
430→                                "Empty Address Queue Test: invalid new_high_element.index"
431→                            );
432→                            assert_eq!(
433→                                event.new_high_element.next_index,
434→                                address_bundle.new_element.next_index,
435→                                "Empty Address Queue Test: invalid new_high_element.next_index"
436→                            );
437→                            assert_eq!(
438→                                event.new_high_element.value,
439→                                bigint_to_be_bytes_array::<32>(&address_bundle.new_element.value)
440→                                    .unwrap(),
441→                                "Empty Address Queue Test: invalid new_high_element.value"
442→                            );
443→                            assert_eq!(
444→                                event.new_high_element.next_value,
445→                                bigint_to_be_bytes_array::<32>(
446→                                    &address_bundle.new_element_next_value
447→                                )
448→                                .unwrap(),
449→                                "Empty Address Queue Test: invalid new_high_element.next_value"
450→                            );
451→                        }
452→                    }
453→                    _ => {
454→                        panic!("Wrong event type.");
455→                    }
456→                }
457→                counter += 1;
458→                true
459→            }
460→            Err(e) => {
461→                update_errors.push(e);
462→                break;
463→            }
464→        };
465→
466→        if update_successful {
467→            if !signer_is_owner {
468→                assert_forester_counter(
469→                    rpc,
470→                    &get_forester_epoch_pda_from_authority(&forester.pubkey(), epoch).0,
471→                    pre_forester_counter,
472→                    1,
473→                )
474→                .await
475→                .unwrap();
476→            }
477→            let merkle_tree =
478→                get_indexed_merkle_tree::<AddressMerkleTreeAccount, R, Poseidon, usize, 26, 16>(
479→                    rpc,
480→                    address_merkle_tree_pubkey,
481→                )
482→                .await
483→                .unwrap();
484→
485→            let (old_low_address, _) = address_tree_bundle
486→                .find_low_element_for_nonexistent(&address.value_biguint())
487→                .unwrap();
488→            let address_bundle = address_tree_bundle
489→                .new_element_with_low_element_index(old_low_address.index, &address.value_biguint())
490→                .unwrap();
491→            let address_queue =
492→                unsafe { get_hash_set::<QueueAccount, R>(rpc, address_queue_pubkey).await }
493→                    .unwrap();
494→
495→            assert_eq!(
496→                address_queue
497→                    .get_bucket(address_hashset_index as usize)
498→                    .unwrap()
499→                    .unwrap()
500→                    .sequence_number()
501→                    .unwrap(),
502→                old_sequence_number + address_queue.sequence_threshold + 2 // We are doing two Merkle tree operations
503→            );
504→
505→            address_tree_bundle
506→                .update(
507→                    &address_bundle.new_low_element,
508→                    &address_bundle.new_element,
509→                    &address_bundle.new_element_next_value,
510→                )
511→                .unwrap();
512→            address_tree_bundle
513→                .append_with_low_element_index(
514→                    address_bundle.new_low_element.index,
515→                    &address_bundle.new_element.value,
516→                )
517→                .unwrap();
518→            assert_eq!(merkle_tree.sequence_number(), old_sequence_number + 2);
519→            assert_ne!(old_root, merkle_tree.root(), "Root did not change.");
520→            assert_eq!(
521→                address_tree_bundle.root(),
522→                merkle_tree.root(),
523→                "Root off-chain onchain inconsistent."
524→            );
525→
526→            let changelog_entry = merkle_tree
527→                .changelog
528→                .get(merkle_tree.changelog_index())
529→                .unwrap();
530→            let path = address_tree_bundle
531→                .get_path_of_leaf(merkle_tree.current_index(), true)
532→                .unwrap();
533→            for (i, path_node) in path.iter().enumerate() {
534→                let changelog_node = changelog_entry.path[i].unwrap();
535→                assert_eq!(changelog_node, *path_node);
536→            }
537→
538→            let indexed_changelog_entry = merkle_tree
539→                .indexed_changelog
540→                .get(merkle_tree.indexed_changelog_index())
541→                .unwrap();
542→            let proof = address_tree_bundle
543→                .get_proof_of_leaf(merkle_tree.current_index(), false)
544→                .unwrap();
545→            assert_eq!(
546→                address_bundle.new_element,
547→                indexed_changelog_entry.element.into(),
548→            );
549→            assert_eq!(indexed_changelog_entry.proof.as_slice(), proof.as_slice());
550→            assert_eq!(
551→                indexed_changelog_entry.changelog_index,
552→                merkle_tree.changelog_index()
553→            );
554→        }
555→    }
556→
557→    if update_errors.is_empty() {
558→        Ok(())
559→    } else {
560→        panic!("Errors: {:?}", update_errors);
561→    }
562→}
