565→pub async fn update_merkle_tree<R: Rpc>(
566→    rpc: &mut R,
567→    forester: &Keypair,
568→    address_queue_pubkey: Pubkey,
569→    address_merkle_tree_pubkey: Pubkey,
570→    value: u16,
571→    low_address_index: u64,
572→    low_address_value: [u8; 32],
573→    low_address_next_index: u64,
574→    low_address_next_value: [u8; 32],
575→    low_address_proof: [[u8; 32]; 16],
576→    changelog_index: Option<u16>,
577→    indexed_changelog_index: Option<u16>,
578→    signer_is_owner: bool,
579→    epoch: u64,
580→    is_metadata_forester: bool,
581→) -> Result<Option<(MerkleTreeEvent, Signature, u64)>, RpcError> {
582→    let changelog_index = match changelog_index {
583→        Some(changelog_index) => changelog_index,
584→        None => {
585→            let address_merkle_tree =
586→                get_indexed_merkle_tree::<AddressMerkleTreeAccount, R, Poseidon, usize, 26, 16>(
587→                    rpc,
588→                    address_merkle_tree_pubkey,
589→                )
590→                .await
591→                .unwrap();
592→
593→            address_merkle_tree.changelog_index() as u16
594→        }
595→    };
596→    let indexed_changelog_index = match indexed_changelog_index {
597→        Some(indexed_changelog_index) => indexed_changelog_index,
598→        None => {
599→            let address_merkle_tree =
600→                get_indexed_merkle_tree::<AddressMerkleTreeAccount, R, Poseidon, usize, 26, 16>(
601→                    rpc,
602→                    address_merkle_tree_pubkey,
603→                )
604→                .await
605→                .unwrap();
606→
607→            address_merkle_tree.indexed_changelog_index() as u16
608→        }
609→    };
610→    let update_ix = if !signer_is_owner {
611→        create_update_address_merkle_tree_instruction(
612→            UpdateAddressMerkleTreeInstructionInputs {
613→                authority: forester.pubkey(),
614→                derivation: forester.pubkey(),
615→                address_merkle_tree: address_merkle_tree_pubkey,
616→                address_queue: address_queue_pubkey,
617→                changelog_index,
618→                indexed_changelog_index,
619→                value,
620→                low_address_index,
621→                low_address_value,
622→                low_address_next_index,
623→                low_address_next_value,
624→                low_address_proof,
625→                is_metadata_forester,
626→            },
627→            epoch,
628→        )
629→    } else {
630→        let instruction_data = UpdateAddressMerkleTree {
631→            changelog_index,
632→            indexed_changelog_index,
633→            value,
634→            low_address_index,
635→            low_address_value,
636→            low_address_next_index,
637→            low_address_next_value,
638→            low_address_proof,
639→        };
640→        Instruction {
641→            program_id: ID,
642→            accounts: vec![
643→                AccountMeta::new(forester.pubkey(), true),
644→                AccountMeta::new(ID, false),
645→                AccountMeta::new(address_queue_pubkey, false),
646→                AccountMeta::new(address_merkle_tree_pubkey, false),
647→                AccountMeta::new(NOOP_PROGRAM_ID, false),
648→            ],
649→            data: instruction_data.data(),
650→        }
651→    };
652→
653→    rpc.create_and_send_transaction_with_event::<MerkleTreeEvent>(
654→        &[update_ix],
655→        &forester.pubkey(),
656→        &[forester],
657→    )
658→    .await
659→}
