 56→pub fn process_nullify_leaves<'a, 'b, 'c: 'info, 'info>(
 57→    ctx: &'a Context<'a, 'b, 'c, 'info, NullifyLeaves<'info>>,
 58→    change_log_indices: &'a [u64],
 59→    leaves_queue_indices: &'a [u16],
 60→    leaf_indices: &'a [u64],
 61→    proofs: &'a [Vec<[u8; 32]>],
 62→) -> Result<()> {
 63→    if change_log_indices.len() != 1 {
 64→        msg!("only implemented for 1 nullifier update");
 65→        return Err(AccountCompressionErrorCode::NumberOfChangeLogIndicesMismatch.into());
 66→    }
 67→    if leaves_queue_indices.len() != change_log_indices.len() {
 68→        msg!("only implemented for 1 nullifier update");
 69→        return Err(AccountCompressionErrorCode::NumberOfLeavesMismatch.into());
 70→    }
 71→    if leaf_indices.len() != change_log_indices.len() {
 72→        msg!("only implemented for 1 nullifier update");
 73→        return Err(AccountCompressionErrorCode::NumberOfIndicesMismatch.into());
 74→    }
 75→    if proofs.len() != change_log_indices.len() {
 76→        msg!("only implemented for 1 nullifier update");
 77→        return Err(AccountCompressionErrorCode::NumberOfProofsMismatch.into());
 78→    }
 79→    if proofs.len() > 1 && proofs[0].len() != proofs[1].len() {
 80→        msg!(
 81→            "Proofs length mismatch {} {}",
 82→            proofs[0].len(),
 83→            proofs[1].len()
 84→        );
 85→        return Err(AccountCompressionErrorCode::ProofLengthMismatch.into());
 86→    }
 87→    insert_nullifier(
 88→        proofs,
 89→        change_log_indices,
 90→        leaves_queue_indices,
 91→        leaf_indices,
 92→        ctx,
 93→    )?;
 94→
 95→    Ok(())
 96→}
