 41→/// Work items should be of only one type and tree
 42→pub async fn fetch_proofs_and_create_instructions<R: Rpc>(
 43→    authority: Pubkey,
 44→    derivation: Pubkey,
 45→    pool: Arc<SolanaRpcPool<R>>,
 46→    epoch: u64,
 47→    work_items: &[WorkItem],
 48→) -> crate::Result<(Vec<MerkleProofType>, Vec<Instruction>)> {
 49→    let mut proofs = Vec::new();
 50→    let mut instructions = vec![];
 51→
 52→    let (address_items, state_items): (Vec<_>, Vec<_>) = work_items
 53→        .iter()
 54→        .partition(|item| matches!(item.tree_account.tree_type, TreeType::AddressV1));
 55→
 56→    for item in state_items.iter() {
 57→        if item.tree_account.tree_type != TreeType::StateV1 {
 58→            warn!(
 59→                event = "v1_state_item_unexpected_tree_type",
 60→                tree_type = ?item.tree_account.tree_type,
 61→                "State item has unexpected tree type"
 62→            );
 63→        }
 64→    }
 65→    let state_items = state_items
 66→        .into_iter()
 67→        .filter(|item| item.tree_account.tree_type == TreeType::StateV1)
 68→        .collect::<Vec<_>>();
 69→
 70→    let address_data = if !address_items.is_empty() {
 71→        let merkle_tree = address_items
 72→            .first()
 73→            .ok_or_else(|| ForesterError::General {
 74→                error: "No address items found".to_string(),
 75→            })?
 76→            .tree_account
 77→            .merkle_tree
 78→            .to_bytes();
 79→        let addresses: Vec<[u8; 32]> = address_items
 80→            .iter()
 81→            .map(|item| item.queue_item_data.hash)
 82→            .collect();
 83→        Some((merkle_tree, addresses))
 84→    } else {
 85→        None
 86→    };
 87→
 88→    let state_data = if !state_items.is_empty() {
 89→        let states: Vec<[u8; 32]> = state_items
 90→            .iter()
 91→            .map(|item| item.queue_item_data.hash)
 92→            .collect();
 93→        Some(states)
 94→    } else {
 95→        None
 96→    };
 97→
 98→    let rpc = pool.get_connection().await?;
 99→    if let Err(e) = wait_for_indexer(&*rpc).await {
100→        if should_emit_rate_limited_warning("v1_wait_for_indexer", Duration::from_secs(30)) {
101→            warn!(
102→                event = "v1_wait_for_indexer_error",
103→                error = %e,
104→                "Indexer not fully caught up, but proceeding anyway"
105→            );
106→        }
107→    }
108→
109→    let address_proofs = if let Some((merkle_tree, addresses)) = address_data {
110→        let total_addresses = addresses.len();
111→        info!(
112→            event = "v1_address_proofs_fetch_started",
113→            requested = total_addresses,
114→            batch_size = ADDRESS_PROOF_BATCH_SIZE,
115→            "Fetching address proofs in batches"
116→        );
117→
118→        let start_time = Instant::now();
119→        let mut all_proofs = Vec::with_capacity(total_addresses);
120→
121→        for (batch_idx, batch) in addresses.chunks(ADDRESS_PROOF_BATCH_SIZE).enumerate() {
122→            let batch_start = Instant::now();
123→            // Pass slice directly if indexer accepts it, otherwise clone
124→            let batch_addresses: Vec<[u8; 32]> = batch.to_vec();
125→            let batch_size = batch_addresses.len();
126→
127→            // Retry loop for transient network errors
128→            let mut last_error = None;
129→            for attempt in 0..=ADDRESS_PROOF_MAX_RETRIES {
130→                if attempt > 0 {
131→                    // Exponential backoff: 500ms, 1000ms, 2000ms
132→                    let delay_ms = ADDRESS_PROOF_RETRY_BASE_DELAY_MS * (1 << (attempt - 1));
133→                    warn!(
134→                        event = "v1_address_proof_batch_retrying",
135→                        batch_index = batch_idx,
136→                        attempt = attempt + 1,
137→                        max_attempts = ADDRESS_PROOF_MAX_RETRIES + 1,
138→                        delay_ms,
139→                        "Retrying address proof batch"
140→                    );
141→                    tokio::time::sleep(std::time::Duration::from_millis(delay_ms)).await;
142→                }
143→
144→                match rpc
145→                    .indexer()?
146→                    .get_multiple_new_address_proofs(merkle_tree, batch_addresses.clone(), None)
147→                    .await
148→                {
149→                    Ok(response) => {
150→                        let batch_duration = batch_start.elapsed();
151→                        let proofs_received = response.value.items.len();
152→
153→                        info!(
154→                            event = "v1_address_proof_batch_completed",
155→                            batch_index = batch_idx,
156→                            requested = batch_size,
157→                            received = proofs_received,
158→                            duration_s = batch_duration.as_secs_f64(),
159→                            retries = attempt,
160→                            "Address proof batch completed"
161→                        );
162→
163→                        if proofs_received != batch_size {
164→                            warn!(
165→                                event = "v1_address_proof_batch_count_mismatch",
166→                                batch_index = batch_idx,
167→                                requested = batch_size,
168→                                received = proofs_received,
169→                                "Address proof count mismatch in batch"
170→                            );
171→                        }
172→
173→                        all_proofs.extend(response.value.items);
174→                        last_error = None;
175→                        break;
176→                    }
177→                    Err(e) => {
178→                        last_error = Some(e);
179→                    }
180→                }
181→            }
182→
183→            // If we exhausted all retries, return the last error
184→            if let Some(e) = last_error {
185→                let batch_duration = batch_start.elapsed();
186→                warn!(
187→                    event = "v1_address_proof_batch_failed",
188→                    batch_index = batch_idx,
189→                    attempts = ADDRESS_PROOF_MAX_RETRIES + 1,
190→                    duration_s = batch_duration.as_secs_f64(),
191→                    error = %e,
192→                    "Failed to get address proofs for batch"
193→                );
194→                return Err(anyhow::anyhow!(
195→                    "Failed to get address proofs for batch {} after {} retries: {}",
196→                    batch_idx,
197→                    ADDRESS_PROOF_MAX_RETRIES,
198→                    e
199→                ));
200→            }
201→        }
202→
203→        let total_duration = start_time.elapsed();
204→        info!(
205→            event = "v1_address_proofs_fetch_completed",
206→            requested = total_addresses,
207→            received = all_proofs.len(),
208→            duration_s = total_duration.as_secs_f64(),
209→            "Address proofs fetch completed"
210→        );
211→
212→        update_indexer_response_time(
213→            "get_multiple_new_address_proofs",
214→            "AddressV1",
215→            total_duration.as_secs_f64(),
216→        );
217→        let tree_pubkey_str = address_items
218→            .first()
219→            .map(|item| item.tree_account.merkle_tree.to_string())
220→            .unwrap_or_default();
221→        update_indexer_proof_count(
222→            "AddressV1",
223→            &tree_pubkey_str,
224→            total_addresses as u64,
225→            all_proofs.len() as u64,
226→        );
227→
228→        all_proofs
229→    } else {
230→        Vec::new()
231→    };
232→
233→    let state_proofs = if let Some(states) = state_data {
234→        let total_states = states.len();
235→        info!(
236→            event = "v1_state_proofs_fetch_started",
237→            requested = total_states,
238→            "Fetching state proofs"
239→        );
240→
241→        let start_time = Instant::now();
242→
243→        // Retry loop for transient network errors
244→        let mut last_error = None;
245→        let mut proofs = None;
246→
247→        for attempt in 0..=ADDRESS_PROOF_MAX_RETRIES {
248→            if attempt > 0 {
249→                // Exponential backoff: 500ms, 1000ms, 2000ms
250→                let delay_ms = ADDRESS_PROOF_RETRY_BASE_DELAY_MS * (1 << (attempt - 1));
251→                warn!(
252→                    event = "v1_state_proofs_retrying",
253→                    attempt = attempt + 1,
254→                    max_attempts = ADDRESS_PROOF_MAX_RETRIES + 1,
255→                    delay_ms,
256→                    "Retrying state proofs"
257→                );
258→                tokio::time::sleep(std::time::Duration::from_millis(delay_ms)).await;
259→            }
260→
261→            match rpc
262→                .indexer()?
263→                .get_multiple_compressed_account_proofs(states.clone(), None)
264→                .await
265→            {
266→                Ok(response) => {
267→                    let duration = start_time.elapsed();
268→                    let proofs_received = response.value.items.len();
269→
270→                    info!(
271→                        event = "v1_state_proofs_fetch_completed",
272→                        requested = total_states,
273→                        received = proofs_received,
274→                        duration_s = duration.as_secs_f64(),
275→                        retries = attempt,
276→                        "State proofs fetch completed"
277→                    );
278→
279→                    if proofs_received != total_states {
280→                        warn!(
281→                            event = "v1_state_proof_count_mismatch",
282→                            requested = total_states,
283→                            received = proofs_received,
284→                            "State proof count mismatch"
285→                        );
286→                    }
287→
288→                    update_indexer_response_time(
289→                        "get_multiple_compressed_account_proofs",
290→                        "StateV1",
291→                        duration.as_secs_f64(),
292→                    );
293→                    let state_tree_pubkey_str = state_items
294→                        .first()
295→                        .map(|item| item.tree_account.merkle_tree.to_string())
296→                        .unwrap_or_default();
297→                    update_indexer_proof_count(
298→                        "StateV1",
299→                        &state_tree_pubkey_str,
300→                        total_states as u64,
301→                        proofs_received as u64,
302→                    );
303→
304→                    proofs = Some(response.value.items);
305→                    last_error = None;
306→                    break;
307→                }
308→                Err(e) => {
309→                    last_error = Some(e);
310→                }
311→            }
312→        }
313→
314→        // If we exhausted all retries, return the last error
315→        if let Some(e) = last_error {
316→            let duration = start_time.elapsed();
317→            warn!(
318→                event = "v1_state_proofs_fetch_failed",
319→                attempts = ADDRESS_PROOF_MAX_RETRIES + 1,
320→                duration_s = duration.as_secs_f64(),
321→                error = %e,
322→                "Failed to get state proofs"
323→            );
324→            return Err(anyhow::anyhow!(
325→                "Failed to get state proofs after {} retries: {}",
326→                ADDRESS_PROOF_MAX_RETRIES,
327→                e
328→            ));
329→        }
330→
331→        proofs.unwrap_or_default()
332→    } else {
333→        Vec::new()
334→    };
335→
336→    if address_proofs.len() != address_items.len() {
337→        return Err(anyhow::anyhow!(
338→            "Address proof count mismatch: requested={}, received={}",
339→            address_items.len(),
340→            address_proofs.len()
341→        ));
342→    }
343→
344→    for (item, proof) in address_items.iter().zip(address_proofs.into_iter()) {
345→        proofs.push(MerkleProofType::AddressProof(proof.clone()));
346→        let instruction = create_update_address_merkle_tree_instruction(
347→            UpdateAddressMerkleTreeInstructionInputs {
348→                authority,
349→                derivation,
350→                address_merkle_tree: item.tree_account.merkle_tree,
351→                address_queue: item.tree_account.queue,
352→                value: item.queue_item_data.index as u16,
353→                low_address_index: proof.low_address_index,
354→                low_address_value: proof.low_address_value,
355→                low_address_next_index: proof.low_address_next_index,
356→                low_address_next_value: proof.low_address_next_value,
357→                low_address_proof: proof.low_address_proof.try_into().map_err(|_| {
358→                    ForesterError::General {
359→                        error: "Failed to convert proof to fixed array".to_string(),
360→                    }
361→                })?,
362→                changelog_index: (proof.root_seq % ADDRESS_MERKLE_TREE_CHANGELOG) as u16,
363→                indexed_changelog_index: (proof.root_seq % ADDRESS_MERKLE_TREE_INDEXED_CHANGELOG)
364→                    as u16,
365→                is_metadata_forester: false,
366→            },
367→            epoch,
368→        );
369→        instructions.push(instruction);
370→    }
371→
372→    // Process state proofs and create instructions
373→    if state_proofs.len() != state_items.len() {
374→        return Err(anyhow::anyhow!(
375→            "State proof count mismatch: requested={}, received={}",
376→            state_items.len(),
377→            state_proofs.len()
378→        ));
379→    }
380→
381→    for (item, proof) in state_items.iter().zip(state_proofs.into_iter()) {
382→        proofs.push(MerkleProofType::StateProof(proof.clone()));
383→
384→        let _debug = false;
385→        if _debug {
386→            let onchain_account = rpc
387→                .get_account(item.tree_account.merkle_tree)
388→                .await?
389→                .ok_or_else(|| {
390→                    anyhow::anyhow!("Tree account {} not found", item.tree_account.merkle_tree)
391→                })?;
392→            let onchain_tree = match account_compression::state_merkle_tree_from_bytes_zero_copy(
393→                &onchain_account.data,
394→            ) {
395→                Ok(tree) => tree,
396→                Err(e) => {
397→                    tracing::error!(
398→                        event = "v1_onchain_tree_deserialize_failed",
399→                        tree = %item.tree_account.merkle_tree,
400→                        error = %e,
401→                        "Failed to deserialize onchain tree"
402→                    );
403→                    return Err(anyhow::anyhow!("Failed to deserialize onchain tree: {}", e));
404→                }
405→            };
406→
407→            let onchain_root = onchain_tree.root();
408→            let onchain_root_index = onchain_tree.root_index();
409→            let onchain_changelog_index = onchain_tree.changelog_index();
410→
411→            tracing::info!(
412→                event = "v1_debug_nullify_instruction",
413→                tree = %item.tree_account.merkle_tree,
414→                hash = %bs58::encode(&item.queue_item_data.hash).into_string(),
415→                leaf_index = proof.leaf_index,
416→                root_seq = proof.root_seq,
417→                changelog_index = proof.root_seq % STATE_MERKLE_TREE_CHANGELOG,
418→                indexer_root = %bs58::encode(&proof.root).into_string(),
419→                "Creating nullify instruction"
420→            );
421→
422→            tracing::info!(
423→                event = "v1_debug_onchain_tree_state",
424→                tree = %item.tree_account.merkle_tree,
425→                current_root = %bs58::encode(&onchain_root).into_string(),
426→                root_index = onchain_root_index,
427→                changelog_index = onchain_changelog_index,
428→                "Onchain tree state"
429→            );
430→
431→            let capacity = onchain_tree.roots.capacity();
432→            let first_index = onchain_tree.roots.first_index();
433→
434→            let root_history: Vec<String> = onchain_tree
435→                .roots
436→                .iter()
437→                .enumerate()
438→                .map(|(offset, root)| {
439→                    let buffer_index = (first_index + offset) % capacity.max(1);
440→                    format!("#{buffer_index}: {}", bs58::encode(root).into_string())
441→                })
442→                .collect();
443→
444→            tracing::info!(
445→                event = "v1_debug_onchain_root_history",
446→                history_len = onchain_tree.roots.len(),
447→                capacity,
448→                root_history = ?root_history,
449→                "Onchain root history"
450→            );
451→
452→            let indexer_root_position =
453→                onchain_tree
454→                    .roots
455→                    .iter()
456→                    .enumerate()
457→                    .find_map(|(offset, root)| {
458→                        (root == &proof.root).then_some((first_index + offset) % capacity.max(1))
459→                    });
460→
461→            tracing::info!(
462→                event = "v1_debug_indexer_root_position",
463→                indexer_root = %bs58::encode(&proof.root).into_string(),
464→                present_at_buffer_index = ?indexer_root_position,
465→                "Indexer root position in onchain buffer"
466→            );
467→
468→            if indexer_root_position.is_none() {
469→                return Err(anyhow::anyhow!(
470→                    "Indexer root {} not found in onchain root history for tree {}. Current root: {}, root_index: {}",
471→                    bs58::encode(&proof.root).into_string(),
472→                    item.tree_account.merkle_tree,
473→                    bs58::encode(&onchain_root).into_string(),
474→                    onchain_root_index
475→                ));
476→            }
477→        }
478→
479→        let instruction = create_nullify_instruction(
480→            CreateNullifyInstructionInputs {
481→                nullifier_queue: item.tree_account.queue,
482→                merkle_tree: item.tree_account.merkle_tree,
483→                change_log_indices: vec![proof.root_seq % STATE_MERKLE_TREE_CHANGELOG],
484→                leaves_queue_indices: vec![item.queue_item_data.index as u16],
485→                indices: vec![proof.leaf_index],
486→                proofs: vec![proof.proof.clone()],
487→                authority,
488→                derivation,
489→                is_metadata_forester: false,
490→            },
491→            epoch,
492→        );
493→        instructions.push(instruction);
494→    }
495→
496→    Ok((proofs, instructions))
497→}
498→
499→/// Request priority fee estimate from Helius RPC endpoint
500→pub async fn request_priority_fee_estimate(
501→    url: &Url,
502→    account_keys: Vec<Pubkey>,
503→) -> crate::Result<u64> {
504→    if url.host_str() != Some("mainnet") {
505→        return Ok(10_000);
506→    }
507→
508→    let priority_fee_request = GetPriorityFeeEstimateRequest {
509→        transaction: None,
510→        account_keys: Some(
511→            account_keys
512→                .iter()
513→                .map(|pubkey| bs58::encode(pubkey).into_string())
514→                .collect(),
515→        ),
516→        options: Some(GetPriorityFeeEstimateOptions {
517→            include_all_priority_fee_levels: None,
518→            recommended: Some(true),
519→            include_vote: None,
520→            lookback_slots: None,
521→            priority_level: None,
522→            transaction_encoding: None,
523→        }),
524→    };
525→
526→    let rpc_request = RpcRequest::new(
527→        "getPriorityFeeEstimate".to_string(),
528→        serde_json::json!({
529→            "get_priority_fee_estimate_request": priority_fee_request
530→        }),
531→    );
532→
533→    let client = reqwest::Client::new();
534→    let response = client
535→        .post(url.clone())
536→        .header("Content-Type", "application/json")
537→        .json(&rpc_request)
538→        .send()
539→        .await?;
540→
541→    let response_text = response.text().await?;
542→
543→    let response: RpcResponse<GetPriorityFeeEstimateResponse> =
544→        serde_json::from_str(&response_text)?;
545→
546→    response
547→        .result
548→        .priority_fee_estimate
549→        .map(|estimate| estimate as u64)
550→        .ok_or(
551→            ForesterError::General {
552→                error: "Priority fee estimate not available".to_string(),
553→            }
554→            .into(),
555→        )
556→}
557→
558→/// Calculate the compute unit price in microLamports based on the target lamports and compute units
559→#[allow(dead_code)]
560→pub fn calculate_compute_unit_price(target_lamports: u64, compute_units: u64) -> u64 {
561→    ((target_lamports * 1_000_000) as f64 / compute_units as f64).ceil() as u64
562→}
563→
564→/// Get a capped priority fee for transaction between min and max.
565→#[allow(dead_code)]
566→pub fn get_capped_priority_fee(cap_config: CapConfig) -> u64 {
567→    if cap_config.max_fee_lamports < cap_config.min_fee_lamports {
568→        warn!(
569→            event = "v1_priority_fee_cap_invalid",
570→            max_fee_lamports = cap_config.max_fee_lamports,
571→            min_fee_lamports = cap_config.min_fee_lamports,
572→            "Invalid priority fee cap config; clamping max to min"
573→        );
574→    }
575→    let max_fee_lamports = cap_config.max_fee_lamports.max(cap_config.min_fee_lamports);
576→
577→    let priority_fee_max =
578→        calculate_compute_unit_price(max_fee_lamports, cap_config.compute_unit_limit);
579→    let priority_fee_min =
580→        calculate_compute_unit_price(cap_config.min_fee_lamports, cap_config.compute_unit_limit);
581→    let capped_fee = std::cmp::min(cap_config.rec_fee_microlamports_per_cu, priority_fee_max);
582→    std::cmp::max(capped_fee, priority_fee_min)
583→}
