240→            .epoch_pda
241→            .protocol_config
242→            .get_current_active_epoch(current_solana_slot)?;
243→        if current_active_epoch != ctx.accounts.epoch_pda.epoch {
244→            return err!(RegistryError::InvalidEpoch);
245→        }
246→        ctx.accounts.forester_epoch_pda.total_epoch_weight =
247→            Some(ctx.accounts.epoch_pda.registered_weight);
248→        ctx.accounts.forester_epoch_pda.finalize_counter += 1;
249→        // Check limit for finalize counter to throw if exceeded
250→        // Is a safeguard so that noone can block parallelism.
251→        // This instruction can be passed with nullify instructions, to prevent
252→        // read locking the epoch account for more than X transactions limit
253→        // the number of syncs without failing the tx to X
254→        if ctx.accounts.forester_epoch_pda.finalize_counter
255→            > ctx
256→                .accounts
257→                .forester_epoch_pda
258→                .protocol_config
259→                .finalize_counter_limit
260→        {
261→            return err!(RegistryError::FinalizeCounterExceeded);
262→        }
263→
264→        Ok(())
265→    }
