284→    pub fn initialize_address_merkle_tree(
285→        ctx: Context<InitializeMerkleTreeAndQueue>,
286→        bump: u8,
287→        program_owner: Option<Pubkey>,
288→        forester: Option<Pubkey>,
289→        merkle_tree_config: AddressMerkleTreeConfig,
290→        queue_config: AddressQueueConfig,
291→    ) -> Result<()> {
292→        // Address V1 trees are deprecated.
293→        // Light foresters (fee-based) are disabled for address V1 trees.
294→        // New address V1 trees must be program owned with a designated forester.
295→        // New address V1 trees must not have network fees.
296→        if program_owner.is_none() {
297→            msg!("Program owner must be defined.");
298→            return err!(RegistryError::ProgramOwnerUndefined);
299→        }
300→        if merkle_tree_config.network_fee.is_some() {
301→            msg!("Network fee must be None.");
302→            return err!(RegistryError::InvalidNetworkFee);
303→        }
304→        // A designated program-owned forester is required for address V1 trees.
305→        // Light foresters (fee-based) will not service address V1 trees.
306→        if forester.is_none() {
307→            msg!("Forester pubkey required for program-owned trees.");
308→            return err!(RegistryError::ForesterUndefined);
309→        }
310→        // Unused parameter
311→        if queue_config.network_fee.is_some() {
312→            return err!(RegistryError::InvalidNetworkFee);
313→        }
314→        process_initialize_address_merkle_tree(
315→            ctx,
316→            bump,
317→            0,
318→            program_owner,
319→            forester,
320→            merkle_tree_config,
321→            queue_config,
322→        )
323→    }
