325→    pub fn initialize_state_merkle_tree(
326→        ctx: Context<InitializeMerkleTreeAndQueue>,
327→        bump: u8,
328→        program_owner: Option<Pubkey>,
329→        forester: Option<Pubkey>,
330→        merkle_tree_config: StateMerkleTreeConfig,
331→        queue_config: NullifierQueueConfig,
332→    ) -> Result<()> {
333→        // Program owned trees are disabled
334→        if program_owner.is_some() {
335→            msg!("Program owner must not be defined.");
336→            return err!(RegistryError::ProgramOwnerDefined);
337→        }
338→        // The network fee must be either zero or the same as the protocol config.
339→        // Only trees with a network fee will be serviced by light foresters.
340→        if let Some(network_fee) = merkle_tree_config.network_fee {
341→            if network_fee != ctx.accounts.protocol_config_pda.config.network_fee {
342→                return err!(RegistryError::InvalidNetworkFee);
343→            }
344→            if forester.is_some() {
345→                msg!("Forester pubkey must not be defined for trees serviced by light foresters.");
346→                return err!(RegistryError::ForesterDefined);
347→            }
348→            if ctx.accounts.authority.key() != ctx.accounts.protocol_config_pda.authority {
349→                return err!(RegistryError::InvalidSigner);
350→            }
351→        } else if forester.is_none() {
352→            msg!("Forester pubkey required for trees without a network fee.");
353→            msg!("Trees without a network fee will not be serviced by light foresters.");
354→            return err!(RegistryError::ForesterUndefined);
355→        }
356→
357→        // Unused parameter
358→        if queue_config.network_fee.is_some() {
359→            return err!(RegistryError::InvalidNetworkFee);
360→        }
361→        check_cpi_context(
362→            ctx.accounts
363→                .cpi_context_account
364→                .as_ref()
365→                .unwrap()
366→                .to_account_info(),
367→            &ctx.accounts.protocol_config_pda.config,
368→        )?;
369→        process_initialize_state_merkle_tree(
370→            &ctx,
371→            bump,
372→            0,
373→            program_owner,
374→            forester,
375→            merkle_tree_config,
376→            queue_config,
377→        )?;
378→
379→        process_initialize_cpi_context(
380→            bump,
381→            ctx.accounts.authority.to_account_info(),
382→            ctx.accounts
383→                .cpi_context_account
384→                .as_ref()
385→                .unwrap()
386→                .to_account_info(),
387→            ctx.accounts.merkle_tree.to_account_info(),
388→            ctx.accounts
389→                .light_system_program
390→                .as_ref()
391→                .unwrap()
392→                .to_account_info(),
393→        )
394→    }
