        &AddressQueueConfig::default(),
        1,
    )
    .await
    .unwrap();

    let queue_tree_pair = (nullifier_queue_pubkey, merkle_tree_pubkey);
    // CHECK 1: no nullifiers as input
    let result =
        insert_into_nullifier_queues(&[], &payer, &payer, &[queue_tree_pair], &mut rpc).await;
    assert_rpc_error(
