pub async fn fail_initialize_state_merkle_tree_and_nullifier_queue_invalid_sizes<R: Rpc>(
    rpc: &mut R,
    payer_pubkey: &Pubkey,
    merkle_tree_keypair: &Keypair,
    queue_keypair: &Keypair,
    merkle_tree_config: &StateMerkleTreeConfig,
