            payer_pubkey,
            merkle_tree_keypair,
            queue_keypair,
            &merkle_tree_config,
            queue_config,
            merkle_tree_size,
            queue_size,
            None,
        )
        .await;
        assert_rpc_error(
            result,
            2,
            AccountCompressionErrorCode::UnsupportedCloseThreshold.into(),
        )
        .unwrap();
    }
    for invalid_sequence_threshold in
        (0..merkle_tree_config.roots_size + SAFETY_MARGIN).step_by(200)
    {
        let mut queue_config = queue_config.clone();
