 44→/// Check compressed_accounts in the queue array which are not nullified yet
 45→/// Iterate over these compressed_accounts and nullify them
 46→///
 47→/// Checks:
 48→/// 1. Value in hashset is marked
 49→/// 2. State tree root is updated
 50→/// 3. TODO: add event is emitted (after rebase)
 51→///    optional: assert that the Merkle tree doesn't change except the updated leaf
 52→pub async fn nullify_compressed_accounts<R: Rpc + TestRpc + Indexer + Indexer>(
 53→    rpc: &mut R,
 54→    forester: &Keypair,
 55→    state_tree_bundle: &mut StateMerkleTreeBundle,
 56→    epoch: u64,
 57→    is_metadata_forester: bool,
 58→) -> Result<(), RpcError> {
 59→    let nullifier_queue = unsafe {
 60→        get_hash_set::<QueueAccount, R>(rpc, state_tree_bundle.accounts.nullifier_queue).await
 61→    }
 62→    .unwrap();
 63→    let pre_forester_counter = if is_metadata_forester {
 64→        0
 65→    } else {
 66→        rpc.get_anchor_account::<ForesterEpochPda>(
 67→            &get_forester_epoch_pda_from_authority(&forester.pubkey(), epoch).0,
 68→        )
 69→        .await
 70→        .unwrap()
 71→        .unwrap()
 72→        .work_counter
 73→    };
 74→    let merkle_tree_account = rpc
 75→        .get_account(state_tree_bundle.accounts.merkle_tree)
 76→        .await
 77→        .unwrap()
 78→        .unwrap();
 79→    let merkle_tree_deserialized =
 80→        StateMerkleTreeAccount::try_deserialize(&mut &merkle_tree_account.data[..]).unwrap();
 81→    let network_fee = merkle_tree_deserialized.metadata.rollover_metadata.network_fee;
 82→
 83→    let pre_queue_lamports = rpc
 84→        .get_account(state_tree_bundle.accounts.nullifier_queue)
 85→        .await
 86→        .unwrap()
 87→        .unwrap()
 88→        .lamports;
 89→
 90→    let onchain_merkle_tree =
 91→        get_concurrent_merkle_tree::<StateMerkleTreeAccount, R, Poseidon, 26>(
 92→            rpc,
 93→            state_tree_bundle.accounts.merkle_tree,
 94→        )
 95→        .await
 96→        .unwrap();
 97→    assert_eq!(
 98→        onchain_merkle_tree.root(),
 99→        state_tree_bundle.merkle_tree.root()
100→    );
101→    let pre_root = onchain_merkle_tree.root();
102→    let change_log_index = onchain_merkle_tree.changelog_index() as u64;
103→
104→    let mut compressed_account_to_nullify = Vec::new();
105→
106→    let first = nullifier_queue.first_no_seq().unwrap();
107→
108→    for i in 0..nullifier_queue.get_capacity() {
109→        let bucket = nullifier_queue.get_bucket(i).unwrap();
110→        if let Some(bucket) = bucket {
111→            if bucket.sequence_number.is_none() {
112→                debug!("element to nullify: {:?}", bucket.value_bytes());
113→                let leaf_index: usize = state_tree_bundle
114→                    .merkle_tree
115→                    .get_leaf_index(&bucket.value_bytes())
116→                    .unwrap();
117→                debug!("leaf_index: {:?}", leaf_index);
118→                compressed_account_to_nullify.push((i, bucket.value_bytes()));
119→            }
120→        }
121→    }
122→
123→    debug!(
124→        "nullifying {:?} accounts ",
125→        compressed_account_to_nullify.len()
126→    );
127→
128→    for (i, (index_in_nullifier_queue, compressed_account)) in
129→        compressed_account_to_nullify.iter().enumerate()
130→    {
131→        let leaf_index: usize = state_tree_bundle
132→            .merkle_tree
133→            .get_leaf_index(compressed_account)
134→            .unwrap();
135→        debug!("nullifying leaf: {:?}", leaf_index);
136→
137→        let proof: Vec<[u8; 32]> = state_tree_bundle
138→            .merkle_tree
139→            .get_proof_of_leaf(leaf_index, false)
140→            .unwrap();
141→        let ix = create_nullify_instruction(
142→            CreateNullifyInstructionInputs {
143→                authority: forester.pubkey(),
144→                nullifier_queue: state_tree_bundle.accounts.nullifier_queue,
145→                merkle_tree: state_tree_bundle.accounts.merkle_tree,
146→                change_log_indices: vec![change_log_index],
147→                leaves_queue_indices: vec![*index_in_nullifier_queue as u16],
148→                indices: vec![leaf_index as u64],
149→                proofs: vec![proof],
150→                derivation: forester.pubkey(),
151→                is_metadata_forester,
152→            },
153→            epoch,
154→        );
155→        let instructions = [ix];
156→
157→        let event = Rpc::create_and_send_transaction_with_event::<MerkleTreeEvent>(
158→            rpc,
159→            &instructions,
160→            &forester.pubkey(),
161→            &[forester],
162→        )
163→        .await?
164→        .unwrap();
165→
166→        match event.0 {
167→            MerkleTreeEvent::V2(event) => {
168→                assert_eq!(event.id, state_tree_bundle.accounts.merkle_tree.to_bytes());
169→                assert_eq!(
170→                    event.seq,
171→                    onchain_merkle_tree.sequence_number() as u64 + 1 + i as u64
172→                );
173→                assert_eq!(event.nullified_leaves_indices.len(), 1);
174→                assert_eq!(event.nullified_leaves_indices[0], leaf_index as u64);
175→            }
176→            _ => {
177→                panic!("Wrong event type.");
178→            }
179→        }
180→
181→        assert_value_is_marked_in_queue(
182→            rpc,
183→            state_tree_bundle,
184→            index_in_nullifier_queue,
185→            compressed_account,
186→        )
187→        .await;
188→    }
189→
190→    let num_nullified = compressed_account_to_nullify.len() as u64;
191→    // Locally nullify all leaves
192→    for (_, compressed_account) in compressed_account_to_nullify.iter() {
193→        let leaf_index = state_tree_bundle
194→            .merkle_tree
195→            .get_leaf_index(compressed_account)
196→            .unwrap();
197→        debug!("locally nullifying leaf_index {}", leaf_index);
198→        debug!("compressed_account {:?}", compressed_account);
199→        debug!(
200→            "merkle tree pubkey {:?}",
201→            state_tree_bundle.accounts.merkle_tree
202→        );
203→
204→        state_tree_bundle
205→            .merkle_tree
206→            .update(&[0u8; 32], leaf_index)
207→            .unwrap();
208→    }
209→    let onchain_merkle_tree =
210→        get_concurrent_merkle_tree::<StateMerkleTreeAccount, R, Poseidon, 26>(
211→            rpc,
212→            state_tree_bundle.accounts.merkle_tree,
213→        )
214→        .await
215→        .unwrap();
216→    assert_eq!(
217→        onchain_merkle_tree.root(),
218→        state_tree_bundle.merkle_tree.root()
219→    );
220→    if !is_metadata_forester {
221→        assert_forester_counter(
222→            rpc,
223→            &get_forester_epoch_pda_from_authority(&forester.pubkey(), epoch).0,
224→            pre_forester_counter,
225→            num_nullified,
226→        )
227→        .await
228→        .unwrap();
229→    }
230→
231→    // Assert network fee reimbursement from queue to forester.
232→    if network_fee > 0 && num_nullified > 0 {
233→        let post_queue_lamports = rpc
234→            .get_account(state_tree_bundle.accounts.nullifier_queue)
235→            .await
236→            .unwrap()
237→            .unwrap()
238→            .lamports;
239→        assert_eq!(
240→            pre_queue_lamports - post_queue_lamports,
241→            num_nullified * network_fee,
242→            "Queue should have paid network_fee * num_nullified to forester"
243→        );
244→    }
245→
246→    // SAFEGUARD: check that the root changed if there was at least one element to nullify
247→    if first.is_some() {
248→        assert_ne!(pre_root, onchain_merkle_tree.root());
249→    }
250→    Ok(())
251→}
252→
253→async fn assert_value_is_marked_in_queue<R: Rpc>(
254→    rpc: &mut R,
255→    state_tree_bundle: &mut StateMerkleTreeBundle,
256→    index_in_nullifier_queue: &usize,
257→    compressed_account: &[u8; 32],
258→) {
259→    let nullifier_queue = unsafe {
260→        get_hash_set::<QueueAccount, R>(rpc, state_tree_bundle.accounts.nullifier_queue).await
261→    }
262→    .unwrap();
263→    let array_element = nullifier_queue
264→        .get_bucket(*index_in_nullifier_queue)
265→        .unwrap()
266→        .unwrap();
267→    assert_eq!(&array_element.value_bytes(), compressed_account);
268→    let onchain_merkle_tree =
269→        get_concurrent_merkle_tree::<StateMerkleTreeAccount, R, Poseidon, 26>(
270→            rpc,
271→            state_tree_bundle.accounts.merkle_tree,
272→        )
273→        .await
274→        .unwrap();
275→    assert_eq!(
276→        array_element.sequence_number(),
277→        Some(
278→            onchain_merkle_tree.sequence_number()
279→                + onchain_merkle_tree.roots.capacity()
280→                + SAFETY_MARGIN as usize
281→        )
282→    );
283→}
