285→pub async fn assert_forester_counter<R: Rpc>(
286→    rpc: &mut R,
287→    pubkey: &Pubkey,
288→    pre: u64,
289→    num_nullified: u64,
290→) -> Result<(), RpcError> {
291→    let account = rpc
292→        .get_anchor_account::<ForesterEpochPda>(pubkey)
293→        .await?
294→        .unwrap();
295→    if account.work_counter != pre + num_nullified {
296→        debug!("account.work_counter: {}", account.work_counter);
297→        debug!("pre: {}", pre);
298→        debug!("num_nullified: {}", num_nullified);
299→        debug!("forester pubkey: {:?}", pubkey);
300→        return Err(RpcError::CustomError(
301→            "ForesterEpochPda counter not updated correctly".to_string(),
302→        ));
303→    }
304→    Ok(())
305→}
