335→    let mut update_errors: Vec<RpcError> = Vec::new();
336→    let address_merkle_tree =
337→        get_indexed_merkle_tree::<AddressMerkleTreeAccount, R, Poseidon, usize, 26, 16>(
338→            rpc,
339→            address_merkle_tree_pubkey,
340→        )
341→        .await
342→        .unwrap();
343→    let indexed_changelog_index = address_merkle_tree.indexed_changelog_index() as u16;
344→    let changelog_index = address_merkle_tree.changelog_index() as u16;
345→
346→    let address_tree_account = rpc
