348→        .await
349→        .map_err(|_| RelayerUpdateError::RpcError)?
350→        .ok_or(RelayerUpdateError::RpcError)?;
351→    let address_tree_deserialized =
352→        AddressMerkleTreeAccount::try_deserialize(&mut &address_tree_account.data[..])
353→            .map_err(|_| RelayerUpdateError::RpcError)?;
354→    let network_fee = address_tree_deserialized
355→        .metadata
356→        .rollover_metadata
357→        .network_fee;
358→
359→    let mut counter = 0;
360→    loop {
361→        let pre_forester_counter = if !signer_is_owner {
362→            rpc.get_anchor_account::<ForesterEpochPda>(
363→                &get_forester_epoch_pda_from_authority(&forester.pubkey(), epoch).0,
364→            )
365→            .await
366→            .map_err(|e| RelayerUpdateError::RpcError)?
367→            .unwrap()
368→            .work_counter
369→        } else {
370→            0
371→        };
372→        let address_merkle_tree =
373→            get_indexed_merkle_tree::<AddressMerkleTreeAccount, R, Poseidon, usize, 26, 16>(
374→                rpc,
375→                address_merkle_tree_pubkey,
376→            )
377→            .await
378→            .unwrap();
379→        assert_eq!(address_tree_bundle.root(), address_merkle_tree.root());
380→        let address_queue =
381→            unsafe { get_hash_set::<QueueAccount, R>(rpc, address_queue_pubkey).await }.unwrap();
382→
383→        let address = address_queue.first_no_seq().unwrap();
384→
385→        if address.is_none() {
386→            break;
387→        }
388→        let (address, address_hashset_index) = address.unwrap();
389→        // Create new element from the dequeued value.
390→        let (old_low_address, old_low_address_next_value) = initial_indexed_array_state
391→            .find_low_element_for_nonexistent(&address.value_biguint())
392→            .unwrap();
