484→                            );
485→                            assert_eq!(
486→                                event.new_high_element.index, address_bundle.new_element.index,
487→                                "Empty Address Queue Test: invalid new_high_element.index"
488→                            );
489→                            assert_eq!(
490→                                event.new_high_element.next_index,
491→                                address_bundle.new_element.next_index,
492→                                "Empty Address Queue Test: invalid new_high_element.next_index"
493→                            );
494→                            assert_eq!(
495→                                event.new_high_element.value,
496→                                bigint_to_be_bytes_array::<32>(&address_bundle.new_element.value)
497→                                    .unwrap(),
498→                                "Empty Address Queue Test: invalid new_high_element.value"
499→                            );
500→                            assert_eq!(
501→                                event.new_high_element.next_value,
502→                                bigint_to_be_bytes_array::<32>(
503→                                    &address_bundle.new_element_next_value
504→                                )
505→                                .unwrap(),
506→                                "Empty Address Queue Test: invalid new_high_element.next_value"
507→                            );
508→                        }
509→                    }
510→                    _ => {
511→                        panic!("Wrong event type.");
512→                    }
513→                }
514→                counter += 1;
515→                true
516→            }
517→            Err(e) => {
518→                update_errors.push(e);
519→                break;
520→            }
521→        };
522→
523→        if update_successful {
524→            if !signer_is_owner {
525→                assert_forester_counter(
526→                    rpc,
527→                    &get_forester_epoch_pda_from_authority(&forester.pubkey(), epoch).0,
528→                    pre_forester_counter,
529→                    1,
530→                )
531→                .await
532→                .unwrap();
533→            }
534→
535→            // Assert network fee reimbursement from queue to forester.
536→            if network_fee > 0 {
537→                let post_queue_lamports = rpc
538→                    .get_account(address_queue_pubkey)
539→                    .await
540→                    .map_err(|_| RelayerUpdateError::RpcError)?
541→                    .ok_or(RelayerUpdateError::RpcError)?
542→                    .lamports;
