598→
599→            let changelog_entry = merkle_tree
600→                .changelog
601→                .get(merkle_tree.changelog_index())
602→                .unwrap();
603→            let path = address_tree_bundle
604→                .get_path_of_leaf(merkle_tree.current_index(), true)
605→                .unwrap();
606→            for (i, path_node) in path.iter().enumerate() {
607→                let changelog_node = changelog_entry.path[i].unwrap();
608→                assert_eq!(changelog_node, *path_node);
609→            }
610→
611→            let indexed_changelog_entry = merkle_tree
612→                .indexed_changelog
613→                .get(merkle_tree.indexed_changelog_index())
614→                .unwrap();
615→            let proof = address_tree_bundle
616→                .get_proof_of_leaf(merkle_tree.current_index(), false)
617→                .unwrap();
618→            assert_eq!(
619→                address_bundle.new_element,
620→                indexed_changelog_entry.element.into(),
621→            );
622→            assert_eq!(indexed_changelog_entry.proof.as_slice(), proof.as_slice());
623→            assert_eq!(
624→                indexed_changelog_entry.changelog_index,
625→                merkle_tree.changelog_index()
626→            );
627→        }
628→    }
629→
630→    if update_errors.is_empty() {
631→        Ok(())
632→    } else {
633→        panic!("Errors: {:?}", update_errors);
634→    }
635→}
