638→pub async fn update_merkle_tree<R: Rpc>(
639→    rpc: &mut R,
640→    forester: &Keypair,
641→    address_queue_pubkey: Pubkey,
642→    address_merkle_tree_pubkey: Pubkey,
643→    value: u16,
644→    low_address_index: u64,
645→    low_address_value: [u8; 32],
646→    low_address_next_index: u64,
647→    low_address_next_value: [u8; 32],
648→    low_address_proof: [[u8; 32]; 16],
649→    changelog_index: Option<u16>,
650→    indexed_changelog_index: Option<u16>,
651→    signer_is_owner: bool,
652→    epoch: u64,
653→    is_metadata_forester: bool,
654→) -> Result<Option<(MerkleTreeEvent, Signature, u64)>, RpcError> {
655→    let changelog_index = match changelog_index {
656→        Some(changelog_index) => changelog_index,
657→        None => {
658→            let address_merkle_tree =
659→                get_indexed_merkle_tree::<AddressMerkleTreeAccount, R, Poseidon, usize, 26, 16>(
660→                    rpc,
661→                    address_merkle_tree_pubkey,
662→                )
663→                .await
664→                .unwrap();
665→
666→            address_merkle_tree.changelog_index() as u16
667→        }
668→    };
669→    let indexed_changelog_index = match indexed_changelog_index {
670→        Some(indexed_changelog_index) => indexed_changelog_index,
671→        None => {
672→            let address_merkle_tree =
673→                get_indexed_merkle_tree::<AddressMerkleTreeAccount, R, Poseidon, usize, 26, 16>(
674→                    rpc,
675→                    address_merkle_tree_pubkey,
676→                )
677→                .await
678→                .unwrap();
679→
680→            address_merkle_tree.indexed_changelog_index() as u16
681→        }
682→    };
683→    let update_ix = if !signer_is_owner {
684→        create_update_address_merkle_tree_instruction(
685→            UpdateAddressMerkleTreeInstructionInputs {
686→                authority: forester.pubkey(),
687→                derivation: forester.pubkey(),
688→                address_merkle_tree: address_merkle_tree_pubkey,
689→                address_queue: address_queue_pubkey,
690→                changelog_index,
691→                indexed_changelog_index,
692→                value,
693→                low_address_index,
694→                low_address_value,
695→                low_address_next_index,
696→                low_address_next_value,
697→                low_address_proof,
698→                is_metadata_forester,
699→            },
700→            epoch,
701→        )
702→    } else {
703→        let instruction_data = UpdateAddressMerkleTree {
704→            changelog_index,
705→            indexed_changelog_index,
706→            value,
707→            low_address_index,
708→            low_address_value,
709→            low_address_next_index,
710→            low_address_next_value,
711→            low_address_proof,
712→        };
713→        Instruction {
714→            program_id: ID,
715→            accounts: vec![
716→                AccountMeta::new(forester.pubkey(), true),
717→                AccountMeta::new(ID, false),
718→                AccountMeta::new(address_queue_pubkey, false),
719→                AccountMeta::new(address_merkle_tree_pubkey, false),
720→                AccountMeta::new(NOOP_PROGRAM_ID, false),
721→            ],
722→            data: instruction_data.data(),
723→        }
724→    };
725→
726→    rpc.create_and_send_transaction_with_event::<MerkleTreeEvent>(
727→        &[update_ix],
728→        &forester.pubkey(),
729→        &[forester],
730→    )
731→    .await
732→}
