  1→use anchor_lang::prelude::*;
  2→use light_bounded_vec::BoundedVec;
  3→use light_concurrent_merkle_tree::event::{MerkleTreeEvent, NullifierEvent};
  4→use light_hasher::zero_bytes::poseidon::ZERO_BYTES;
  5→
  6→use crate::{
  7→    emit_indexer_event,
  8→    errors::AccountCompressionErrorCode,
  9→    state::{
 10→        queue::{queue_from_bytes_zero_copy_mut, QueueAccount},
 11→        StateMerkleTreeAccount,
 12→    },
 13→    state_merkle_tree_from_bytes_zero_copy_mut,
 14→    utils::{
 15→        check_signer_is_registered_or_authority::{
 16→            check_signer_is_registered_or_authority, GroupAccess, GroupAccounts,
 17→        },
 18→        transfer_lamports::transfer_lamports,
 19→    },
 20→    RegisteredProgram,
 21→};
 22→
 23→#[derive(Accounts)]
 24→pub struct NullifyLeaves<'info> {
 25→    /// CHECK: should only be accessed by a registered program or owner.
 26→    pub authority: Signer<'info>,
 27→    pub registered_program_pda: Option<Account<'info, RegisteredProgram>>,
 28→    /// CHECK: when emitting event.
 29→    pub log_wrapper: UncheckedAccount<'info>,
 30→    #[account(mut)]
 31→    pub merkle_tree: AccountLoader<'info, StateMerkleTreeAccount>,
 32→    #[account(mut)]
 33→    pub nullifier_queue: AccountLoader<'info, QueueAccount>,
 34→    /// CHECK: receives network fee reimbursement.
 35→    #[account(mut)]
 36→    pub fee_payer: Option<UncheckedAccount<'info>>,
 37→}
 38→
 39→impl GroupAccess for StateMerkleTreeAccount {
 40→    fn get_owner(&self) -> Pubkey {
 41→        self.metadata.access_metadata.owner.into()
 42→    }
 43→
 44→    fn get_program_owner(&self) -> Pubkey {
 45→        self.metadata
 46→            .access_metadata
 47→            .program_owner
 48→            .to_bytes()
 49→            .into()
 50→    }
 51→}
 52→
 53→impl<'info> GroupAccounts<'info> for NullifyLeaves<'info> {
 54→    fn get_authority(&self) -> &Signer<'info> {
 55→        &self.authority
 56→    }
 57→    fn get_registered_program_pda(&self) -> &Option<Account<'info, RegisteredProgram>> {
 58→        &self.registered_program_pda
 59→    }
 60→}
 61→
 62→pub fn process_nullify_leaves<'a, 'b, 'c: 'info, 'info>(
 63→    ctx: &'a Context<'a, 'b, 'c, 'info, NullifyLeaves<'info>>,
 64→    change_log_indices: &'a [u64],
 65→    leaves_queue_indices: &'a [u16],
 66→    leaf_indices: &'a [u64],
 67→    proofs: &'a [Vec<[u8; 32]>],
 68→) -> Result<()> {
 69→    if change_log_indices.len() != 1 {
 70→        msg!("only implemented for 1 nullifier update");
 71→        return Err(AccountCompressionErrorCode::NumberOfChangeLogIndicesMismatch.into());
 72→    }
 73→    if leaves_queue_indices.len() != change_log_indices.len() {
 74→        msg!("only implemented for 1 nullifier update");
 75→        return Err(AccountCompressionErrorCode::NumberOfLeavesMismatch.into());
 76→    }
 77→    if leaf_indices.len() != change_log_indices.len() {
 78→        msg!("only implemented for 1 nullifier update");
 79→        return Err(AccountCompressionErrorCode::NumberOfIndicesMismatch.into());
 80→    }
 81→    if proofs.len() != change_log_indices.len() {
 82→        msg!("only implemented for 1 nullifier update");
 83→        return Err(AccountCompressionErrorCode::NumberOfProofsMismatch.into());
 84→    }
 85→    if proofs.len() > 1 && proofs[0].len() != proofs[1].len() {
 86→        msg!(
 87→            "Proofs length mismatch {} {}",
 88→            proofs[0].len(),
 89→            proofs[1].len()
 90→        );
 91→        return Err(AccountCompressionErrorCode::ProofLengthMismatch.into());
 92→    }
 93→    insert_nullifier(
 94→        proofs,
 95→        change_log_indices,
 96→        leaves_queue_indices,
 97→        leaf_indices,
 98→        ctx,
 99→    )?;
100→
101→    if let Some(fee_payer) = ctx.accounts.fee_payer.as_ref() {
102→        let merkle_tree_account = ctx.accounts.merkle_tree.load()?;
103→        let network_fee = merkle_tree_account.metadata.rollover_metadata.network_fee;
104→        if network_fee > 0 {
105→            transfer_lamports(
106→                &ctx.accounts.nullifier_queue.to_account_info(),
107→                &fee_payer.to_account_info(),
108→                network_fee,
109→            )?;
110→        }
111→    }
112→
113→    Ok(())
114→}
115→
116→#[inline(never)]
117→fn insert_nullifier<'a, 'c: 'info, 'info>(
118→    proofs: &[Vec<[u8; 32]>],
119→    change_log_indices: &[u64],
120→    leaves_queue_indices: &[u16],
121→    leaf_indices: &[u64],
122→    ctx: &Context<'a, '_, 'c, 'info, NullifyLeaves<'info>>,
123→) -> Result<()> {
124→    {
125→        let merkle_tree = ctx.accounts.merkle_tree.load()?;
126→
127→        if merkle_tree.metadata.associated_queue != ctx.accounts.nullifier_queue.key() {
128→            msg!(
129→            "Merkle tree and nullifier queue are not associated. Merkle tree associated nullifier queue {:?} != nullifier queue {}",
130→            merkle_tree.metadata.associated_queue,
131→            ctx.accounts.nullifier_queue.key()
132→        );
133→            return err!(AccountCompressionErrorCode::MerkleTreeAndQueueNotAssociated);
134→        }
135→        check_signer_is_registered_or_authority::<NullifyLeaves, StateMerkleTreeAccount>(
136→            ctx,
137→            &merkle_tree,
138→        )?;
139→    }
140→
141→    let merkle_tree = ctx.accounts.merkle_tree.to_account_info();
142→    let mut merkle_tree = merkle_tree.try_borrow_mut_data()?;
143→    let mut merkle_tree = state_merkle_tree_from_bytes_zero_copy_mut(&mut merkle_tree)?;
144→
145→    let nullifier_queue = ctx.accounts.nullifier_queue.to_account_info();
146→    let mut nullifier_queue = nullifier_queue.try_borrow_mut_data()?;
147→    let mut nullifier_queue = unsafe { queue_from_bytes_zero_copy_mut(&mut nullifier_queue)? };
148→
149→    let allowed_proof_size = merkle_tree.height - merkle_tree.canopy_depth;
150→    if proofs[0].len() != allowed_proof_size {
151→        msg!(
152→            "Invalid Proof Length {} allowed height {} - canopy {} {}",
153→            proofs[0].len(),
154→            merkle_tree.height,
155→            merkle_tree.canopy_depth,
156→            allowed_proof_size,
157→        );
158→        return err!(AccountCompressionErrorCode::InvalidMerkleProof);
159→    }
160→    let seq = (merkle_tree.sequence_number() + 1) as u64;
161→    for (i, leaf_queue_index) in leaves_queue_indices.iter().enumerate() {
162→        let leaf_cell = nullifier_queue
163→            .get_unmarked_bucket(*leaf_queue_index as usize)
164→            .ok_or(AccountCompressionErrorCode::LeafNotFound)?
